			winRate: Math.round(winRate * 100) / 100,
			profitFactor: Math.round(profitFactor * 100) / 100,
			totalTrades,
			sortinoRatio: Math.round(sortinoRatio * 100) / 100,
			cagr: Math.round(cagr * 100) / 100,
		},
		equity_curve: equityCurve,
		trade_log: tradeLog,
		signals,
		config,
	};
}

